import requests
from django.conf import settings
from decimal import Decimal


class PayPalService:
    """
    Servicio para integración con PayPal Sandbox.
    """

    def __init__(self):
        self.sandbox_mode = getattr(settings, 'PAYPAL_SANDBOX_MODE', True)
        self.client_id = getattr(settings, 'PAYPAL_CLIENT_ID', '')
        self.client_secret = getattr(settings, 'PAYPAL_CLIENT_SECRET', '')

        if self.sandbox_mode:
            self.base_url = 'https://api.sandbox.paypal.com'
        else:
            self.base_url = 'https://api.paypal.com'

    def crear_pago(self, reserva_id, importe, return_url, cancel_url):
        """
        Crea un pago en PayPal.

        Args:
            reserva_id: ID de la reserva
            importe: Importe a pagar
            return_url: URL de retorno después del pago
            cancel_url: URL de cancelación

        Returns:
            URL de aprobación de PayPal o None si falla
        """
        try:
            headers = {
                'Content-Type': 'application/json',
            }

            payload = {
                'intent': 'sale',
                'payer': {
                    'payment_method': 'paypal',
                },
                'transactions': [
                    {
                        'amount': {
                            'total': str(importe),
                            'currency': 'EUR',
                        },
                        'description': f'Reserva {reserva_id}',
                    }
                ],
                'redirect_urls': {
                    'return_url': return_url,
                    'cancel_url': cancel_url,
                },
            }

            response = requests.post(
                f'{self.base_url}/v1/payments/payment',
                json=payload,
                headers=headers,
                auth=(self.client_id, self.client_secret),
                timeout=10
            )

            if response.status_code == 201:
                data = response.json()
                for link in data.get('links', []):
                    if link['rel'] == 'approval_url':
                        return link['href']

            return None
        except Exception as e:
            print(f'Error en PayPal: {e}')
            return None

    def ejecutar_pago(self, payment_id, payer_id):
        """
        Ejecuta un pago aprobado en PayPal.

        Args:
            payment_id: ID del pago
            payer_id: ID del pagador

        Returns:
            True si el pago se ejecutó correctamente, False en caso contrario
        """
        try:
            headers = {
                'Content-Type': 'application/json',
            }

            payload = {
                'payer_id': payer_id,
            }

            response = requests.post(
                f'{self.base_url}/v1/payments/payment/{payment_id}/execute',
                json=payload,
                headers=headers,
                auth=(self.client_id, self.client_secret),
                timeout=10
            )

            return response.status_code == 200
        except Exception as e:
            print(f'Error ejecutando pago en PayPal: {e}')
            return False

from django.shortcuts import render, redirect, get_object_or_404
from django.views import View
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.utils.decorators import method_decorator
from django.utils import timezone
from datetime import datetime
import uuid
from catalog.models import Barco
from cart.services import get_cart, clear_cart
from .models import Reserva, LineaReserva
from .forms import ReservationStep1Form, ReservationStep2Form, ReservationStep3Form
from .services.pricing import calcular_tarifa
from .services.email import enviar_confirmacion_reserva
from .services.paypal import PayPalService


class ReservationStep1View(View):
    """Vista para el paso 1 de la reserva (datos de cliente)."""

    def get(self, request):
        form = ReservationStep1Form()
        if request.user.is_authenticated:
            form.fields['nombre_cliente'].initial = request.user.get_full_name() or request.user.username
            form.fields['email_contacto'].initial = request.user.email
        return render(request, 'reservations/step1.html', {'form': form})

    def post(self, request):
        form = ReservationStep1Form(request.POST)
        if form.is_valid():
            request.session['reservation_step1'] = {
                'nombre_cliente': form.cleaned_data['nombre_cliente'],
                'email_contacto': form.cleaned_data['email_contacto'],
                'telefono': form.cleaned_data['telefono'],
            }
            return redirect('reservations:step2')
        return render(request, 'reservations/step1.html', {'form': form})


class ReservationStep2View(View):
    """Vista para el paso 2 de la reserva (fechas)."""

    def get(self, request):
        if 'reservation_step1' not in request.session:
            return redirect('reservations:step1')
        form = ReservationStep2Form()
        return render(request, 'reservations/step2.html', {'form': form})

    def post(self, request):
        if 'reservation_step1' not in request.session:
            return redirect('reservations:step1')
        form = ReservationStep2Form(request.POST)
        if form.is_valid():
            request.session['reservation_step2'] = {
                'fecha_inicio': form.cleaned_data['fecha_inicio'].isoformat(),
                'fecha_fin': form.cleaned_data['fecha_fin'].isoformat(),
            }
            return redirect('reservations:step3')
        return render(request, 'reservations/step2.html', {'form': form})


class ReservationStep3View(View):
    """Vista para el paso 3 de la reserva (método de pago)."""

    def get(self, request):
        if 'reservation_step1' not in request.session or 'reservation_step2' not in request.session:
            return redirect('reservations:step1')
        form = ReservationStep3Form()
        cart = get_cart(request)
        if not cart:
            messages.error(request, 'La cesta está vacía.')
            return redirect('cart:view')

        step2 = request.session['reservation_step2']
        fecha_inicio = datetime.fromisoformat(step2['fecha_inicio']).date()
        fecha_fin = datetime.fromisoformat(step2['fecha_fin']).date()

        importe_total, detalles_lineas = calcular_tarifa(cart, fecha_inicio, fecha_fin)

        context = {
            'form': form,
            'importe_total': importe_total,
            'detalles_lineas': detalles_lineas,
        }
        return render(request, 'reservations/step3.html', context)

    def post(self, request):
        if 'reservation_step1' not in request.session or 'reservation_step2' not in request.session:
            return redirect('reservations:step1')
        form = ReservationStep3Form(request.POST)
        if form.is_valid():
            cart = get_cart(request)
            if not cart:
                messages.error(request, 'La cesta está vacía.')
                return redirect('cart:view')

            step1 = request.session['reservation_step1']
            step2 = request.session['reservation_step2']
            metodo_pago = form.cleaned_data['metodo_pago']

            fecha_inicio = datetime.fromisoformat(step2['fecha_inicio']).date()
            fecha_fin = datetime.fromisoformat(step2['fecha_fin']).date()

            importe_total, detalles_lineas = calcular_tarifa(cart, fecha_inicio, fecha_fin)

            codigo_seguimiento = str(uuid.uuid4())[:8].upper()
            reserva = Reserva.objects.create(
                codigo_seguimiento=codigo_seguimiento,
                cliente=request.user if request.user.is_authenticated else None,
                nombre_cliente=step1['nombre_cliente'],
                email_contacto=step1['email_contacto'],
                telefono=step1['telefono'],
                metodo_pago=metodo_pago,
                importe_total=importe_total,
                fecha_inicio=fecha_inicio,
                fecha_fin=fecha_fin,
                cantidad_barcos=len(cart),
            )

            for detalle in detalles_lineas:
                LineaReserva.objects.create(
                    reserva=reserva,
                    barco=detalle['barco'],
                    cantidad=detalle['cantidad'],
                    precio_unitario_dia=detalle['precio_unitario_dia'],
                    tasa_combustible_dia=detalle['tasa_combustible_dia'],
                )

            enviar_confirmacion_reserva(reserva)

            if metodo_pago == 'PAYPAL':
                paypal_service = PayPalService()
                return_url = request.build_absolute_uri('reservations:paypal_return')
                cancel_url = request.build_absolute_uri('reservations:paypal_cancel')
                approval_url = paypal_service.crear_pago(
                    reserva.id,
                    importe_total,
                    return_url,
                    cancel_url
                )
                if approval_url:
                    request.session['reserva_id'] = reserva.id
                    request.session.modified = True
                    return redirect(approval_url)
                else:
                    messages.warning(request, 'No se pudo procesar el pago con PayPal. Por favor, intente de nuevo.')
                    reserva.delete()
                    return redirect('reservations:step3')
            else:
                reserva.estado = 'PENDIENTE_DE_PAGO'
                reserva.save()

            clear_cart(request)
            del request.session['reservation_step1']
            del request.session['reservation_step2']
            request.session.modified = True

            messages.success(request, 'Reserva creada exitosamente.')
            return redirect('reservations:confirmation')

        step2 = request.session.get('reservation_step2', {})
        if step2:
            fecha_inicio = datetime.fromisoformat(step2['fecha_inicio']).date()
            fecha_fin = datetime.fromisoformat(step2['fecha_fin']).date()
            cart = get_cart(request)
            importe_total, detalles_lineas = calcular_tarifa(cart, fecha_inicio, fecha_fin)
        else:
            importe_total = 0
            detalles_lineas = []

        context = {
            'form': form,
            'importe_total': importe_total,
            'detalles_lineas': detalles_lineas,
        }
        return render(request, 'reservations/step3.html', context)


class ReservationConfirmationView(View):
    """Vista para mostrar la confirmación de la reserva."""

    def get(self, request):
        return render(request, 'reservations/confirmation.html')


class TrackingView(View):
    """Vista para seguimiento de reserva por código."""

    def get(self, request):
        return render(request, 'reservations/tracking.html')

    def post(self, request):
        codigo = request.POST.get('codigo_seguimiento', '').strip()
        if not codigo:
            messages.error(request, 'Por favor, ingresa un código de seguimiento.')
            return render(request, 'reservations/tracking.html')

        try:
            reserva = Reserva.objects.get(codigo_seguimiento=codigo)
            context = {'reserva': reserva}
            return render(request, 'reservations/tracking.html', context)
        except Reserva.DoesNotExist:
            messages.error(request, 'Reserva no encontrada.')
            return render(request, 'reservations/tracking.html')


class MyReservationsView(View):
    """Vista para mostrar las reservas del usuario autenticado."""

    @method_decorator(login_required)
    def get(self, request):
        reservas = Reserva.objects.filter(cliente=request.user).order_by('-fecha_creacion')
        context = {'reservas': reservas}
        return render(request, 'reservations/my_reservations.html', context)


class PayPalReturnView(View):
    """Vista para retorno de PayPal."""

    def get(self, request):
        reserva_id = request.session.get('reserva_id')
        if reserva_id:
            try:
                reserva = Reserva.objects.get(id=reserva_id)
                reserva.estado = 'PAGADO'
                reserva.save()
                del request.session['reserva_id']
                request.session.modified = True
                messages.success(request, 'Pago realizado exitosamente.')
            except Reserva.DoesNotExist:
                messages.error(request, 'No se encontró la reserva.')
        return redirect('/')


class PayPalCancelView(View):
    """Vista para cancelación de PayPal."""

    def get(self, request):
        reserva_id = request.session.get('reserva_id')
        if reserva_id:
            try:
                reserva = Reserva.objects.get(id=reserva_id)
                reserva.delete()
                del request.session['reserva_id']
                request.session.modified = True
            except Reserva.DoesNotExist:
                pass
        messages.error(request, 'Pago cancelado.')
        return redirect('cart:view')

from django.shortcuts import render, redirect, get_object_or_404
from django.views import View
from django.contrib import messages
from django.contrib.auth.models import User
from django.contrib.auth.decorators import login_required, user_passes_test
from django.utils.decorators import method_decorator
from catalog.models import Barco
from reservations.models import Reserva
from cart.services import clear_cart
from .forms import BoatForm, ReservationStateForm
from .services import puede_eliminar_cliente, obtener_estadisticas_admin


def es_admin(user):
    """Verifica si el usuario es administrador."""
    return user.is_staff and user.is_superuser


class AdminDashboardView(View):
    """Vista del panel de administración."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def get(self, request):
        clear_cart(request)
        estadisticas = obtener_estadisticas_admin()
        context = {'estadisticas': estadisticas}
        return render(request, 'admin_panel/dashboard.html', context)


class AdminBoatsListView(View):
    """Vista para listar barcos en el panel de administración."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def get(self, request):
        barcos = Barco.objects.all()
        context = {'barcos': barcos}
        return render(request, 'admin_panel/boats_list.html', context)


class AdminBoatCreateView(View):
    """Vista para crear un barco."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def get(self, request):
        form = BoatForm()
        return render(request, 'admin_panel/boat_form.html', {'form': form, 'titulo': 'Crear Barco'})

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def post(self, request):
        form = BoatForm(request.POST, request.FILES)
        if form.is_valid():
            form.save()
            messages.success(request, 'Barco creado exitosamente.')
            return redirect('admin_panel:boats_list')
        return render(request, 'admin_panel/boat_form.html', {'form': form, 'titulo': 'Crear Barco'})


class AdminBoatEditView(View):
    """Vista para editar un barco."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def get(self, request, id):
        barco = get_object_or_404(Barco, id=id)
        form = BoatForm(instance=barco)
        return render(request, 'admin_panel/boat_form.html', {'form': form, 'barco': barco, 'titulo': 'Editar Barco'})

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def post(self, request, id):
        barco = get_object_or_404(Barco, id=id)
        form = BoatForm(request.POST, request.FILES, instance=barco)
        if form.is_valid():
            form.save()
            messages.success(request, 'Barco actualizado exitosamente.')
            return redirect('admin_panel:boats_list')
        return render(request, 'admin_panel/boat_form.html', {'form': form, 'barco': barco, 'titulo': 'Editar Barco'})


class AdminBoatDeleteView(View):
    """Vista para eliminar un barco."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def post(self, request, id):
        barco = get_object_or_404(Barco, id=id)
        barco.delete()
        messages.success(request, 'Barco eliminado exitosamente.')
        return redirect('admin_panel:boats_list')


class AdminClientsListView(View):
    """Vista para listar clientes."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def get(self, request):
        clientes = User.objects.filter(is_staff=False, is_superuser=False)
        context = {'clientes': clientes}
        return render(request, 'admin_panel/clients_list.html', context)


class AdminClientDeleteView(View):
    """Vista para eliminar un cliente."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def post(self, request, id):
        cliente = get_object_or_404(User, id=id)
        puede_eliminar, mensaje = puede_eliminar_cliente(id)

        if puede_eliminar:
            cliente.delete()
            messages.success(request, 'Cliente eliminado exitosamente.')
        else:
            messages.error(request, mensaje)

        return redirect('admin_panel:clients_list')


class AdminReservationsListView(View):
    """Vista para listar reservas."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def get(self, request):
        reservas = Reserva.objects.all().order_by('-fecha_creacion')
        context = {'reservas': reservas}
        return render(request, 'admin_panel/reservations_list.html', context)


class AdminReservationDetailView(View):
    """Vista para ver detalles de una reserva."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def get(self, request, id):
        reserva = get_object_or_404(Reserva, id=id)
        form = ReservationStateForm(initial={'estado': reserva.estado})
        context = {'reserva': reserva, 'form': form}
        return render(request, 'admin_panel/reservation_detail.html', context)


class AdminReservationChangeStateView(View):
    """Vista para cambiar el estado de una reserva."""

    @method_decorator(login_required)
    @method_decorator(user_passes_test(es_admin))
    def post(self, request, id):
        reserva = get_object_or_404(Reserva, id=id)
        form = ReservationStateForm(request.POST)

        if form.is_valid():
            nuevo_estado = form.cleaned_data['estado']
            reserva.estado = nuevo_estado
            reserva.save()
            messages.success(request, f'Estado de la reserva actualizado a {reserva.get_estado_display()}.')
        else:
            messages.error(request, 'Error al actualizar el estado.')

        return redirect('admin_panel:reservation_detail', id=id)

